import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface IdentificationResult {
  itemName: string;
}

export interface PriceResult {
  priceInfo: string;
  sources: { title: string; uri: string }[];
}

export const identifyItem = async (base64Image: string): Promise<IdentificationResult> => {
  const ai = getAIClient();
  const prompt = "You are an expert guide at the Dalat Night Market in Vietnam. Identify the main food or souvenir item in this image. Respond ONLY with the name of the item in English.";

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: prompt }
      ]
    }
  });

  return { itemName: response.text?.trim() || 'Unknown Item' };
};

export const getAveragePrice = async (itemName: string): Promise<PriceResult> => {
  const ai = getAIClient();
  const prompt = `What is the current average market price for "${itemName}" at local markets in Dalat, Vietnam? Provide a concise summary of the typical price range in VND. Use Google Search to ensure accuracy.`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || 'Source',
    uri: chunk.web?.uri || '#'
  })) || [];

  return {
    priceInfo: response.text || "Could not find specific price information.",
    sources
  };
};

