import React, { useState, useRef, useCallback, useEffect } from 'react';
import { 
  Camera, 
  RotateCcw, 
  CheckCircle, 
  XCircle, 
  Search, 
  Info,
  Loader2,
  ExternalLink,
  ChevronRight
} from 'lucide-react';
import { identifyItem, getAveragePrice, PriceResult } from '../services/geminiService';

enum ScanState {
  IDLE,
  CAPTURING,
  IDENTIFYING,
  CONFIRMING,
  SEARCHING,
  RESULT
}

const ScannerTab: React.FC = () => {
  const [state, setState] = useState<ScanState>(ScanState.IDLE);
  const [image, setImage] = useState<string | null>(null);
  const [itemName, setItemName] = useState<string>('');
  const [priceData, setPriceData] = useState<PriceResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setState(ScanState.CAPTURING);
    } catch (err) {
      console.error(err);
      setError("Unable to access camera. Please allow permissions.");
    }
  };

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        setImage(dataUrl);

        // Stop stream
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());

        handleIdentify(dataUrl.split(',')[1]);
      }
    }
  };

  const handleIdentify = async (base64: string) => {
    setState(ScanState.IDENTIFYING);
    try {
      const result = await identifyItem(base64);
      setItemName(result.itemName);
      setState(ScanState.CONFIRMING);
    } catch (err) {
      setError("Failed to identify item. Try again.");
      setState(ScanState.IDLE);
    }
  };

  const handleConfirm = async () => {
    setState(ScanState.SEARCHING);
    try {
      const result = await getAveragePrice(itemName);
      setPriceData(result);
      setState(ScanState.RESULT);
    } catch (err) {
      setError("Failed to fetch price data.");
      setState(ScanState.CONFIRMING);
    }
  };

  const reset = () => {
    setImage(null);
    setItemName('');
    setPriceData(null);
    setError(null);
    setState(ScanState.IDLE);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 text-white overflow-hidden animate-in fade-in duration-500">
      {/* Header */}
      <div className="p-4 bg-slate-800/80 backdrop-blur-md border-b border-slate-700 flex justify-between items-center z-20">
        <h1 className="font-bold flex items-center gap-2">
          <Camera className="w-5 h-5 text-indigo-400" />
          AI Price Scanner
        </h1>
        {state !== ScanState.IDLE && (
          <button onClick={reset} className="p-2 rounded-full hover:bg-slate-700">
            <RotateCcw className="w-5 h-5" />
          </button>
        )}
      </div>

      <div className="flex-1 relative flex flex-col items-center justify-center p-6 overflow-y-auto pb-24">
        {error && (
          <div className="absolute top-20 left-6 right-6 bg-red-500/90 text-white p-4 rounded-xl flex items-center gap-3 z-50">
            <XCircle className="w-6 h-6 flex-shrink-0" />
            <p className="text-sm font-medium">{error}</p>
          </div>
        )}

        {state === ScanState.IDLE && (
          <div className="text-center space-y-6">
            <div className="w-24 h-24 bg-indigo-500/20 rounded-full flex items-center justify-center mx-auto ring-4 ring-indigo-500/10">
              <Camera className="w-12 h-12 text-indigo-400" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Unsure about the price?</h2>
              <p className="text-slate-400 mt-2">Point your camera at any item in the Dalat market to get fair pricing advice.</p>
            </div>
            <button 
              onClick={startCamera}
              className="px-8 py-4 bg-indigo-600 hover:bg-indigo-500 rounded-full font-bold shadow-lg shadow-indigo-600/30 transition-all active:scale-95"
            >
              Start Scanning
            </button>
          </div>
        )}

        {state === ScanState.CAPTURING && (
          <div className="w-full h-full absolute inset-0 bg-black flex flex-col">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover"
            />
            <div className="absolute bottom-10 left-0 right-0 flex justify-center p-6">
              <button 
                onClick={captureImage}
                className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center p-1"
              >
                <div className="w-full h-full bg-white rounded-full hover:bg-slate-200 transition-colors" />
              </button>
            </div>
          </div>
        )}

        {(state === ScanState.IDENTIFYING || state === ScanState.SEARCHING) && (
          <div className="text-center space-y-6">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-indigo-500/30 rounded-full border-t-indigo-500 animate-spin mx-auto" />
              <Loader2 className="w-12 h-12 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
            </div>
            <div className="space-y-1">
              <p className="text-lg font-semibold animate-pulse">
                {state === ScanState.IDENTIFYING ? 'Recognizing item...' : 'Grounding price data...'}
              </p>
              <p className="text-sm text-slate-400">Powered by Gemini & Google Search</p>
            </div>
          </div>
        )}

        {state === ScanState.CONFIRMING && (
          <div className="w-full space-y-6 max-w-sm animate-in zoom-in-95 duration-300">
            <div className="relative rounded-3xl overflow-hidden shadow-2xl border-2 border-slate-700 bg-slate-800">
              <img src={image!} alt="Captured item" className="w-full h-64 object-cover" />
              <div className="p-4 bg-slate-800/95 backdrop-blur-sm border-t border-slate-700">
                <p className="text-xs font-bold text-indigo-400 uppercase tracking-widest">Item Identified</p>
                <h3 className="text-2xl font-bold mt-1 text-white capitalize">{itemName}</h3>
              </div>
            </div>
            <div className="space-y-4">
              <p className="text-center text-slate-400 text-sm">Is this correct? We'll use this name for price searching.</p>
              <div className="flex gap-4">
                <button 
                  onClick={reset}
                  className="flex-1 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl font-semibold border border-slate-600 transition-all flex items-center justify-center gap-2"
                >
                  <XCircle className="w-5 h-5 text-red-400" />
                  No
                </button>
                <button 
                  onClick={handleConfirm}
                  className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl font-bold shadow-lg shadow-indigo-600/20 transition-all flex items-center justify-center gap-2"
                >
                  <CheckCircle className="w-5 h-5 text-white" />
                  Yes, search!
                </button>
              </div>
            </div>
          </div>
        )}

        {state === ScanState.RESULT && priceData && (
          <div className="w-full space-y-6 max-w-md animate-in slide-in-from-bottom-10 duration-500">
            <div className="bg-white text-slate-900 rounded-3xl p-6 shadow-2xl relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <Search className="w-24 h-24 text-indigo-900" />
              </div>

              <div className="flex items-center gap-3 mb-6">
                <div className="bg-indigo-100 p-2 rounded-xl text-indigo-600">
                  <Info className="w-5 h-5" />
                </div>
                <h2 className="text-xl font-bold text-slate-800">Price Intelligence</h2>
              </div>

              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 mb-6">
                <p className="text-slate-700 leading-relaxed font-medium">
                  {priceData.priceInfo}
                </p>
              </div>

              {priceData.sources.length > 0 && (
                <div className="space-y-3">
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Web References</p>
                  <div className="space-y-2">
                    {priceData.sources.map((source, i) => (
                      <a 
                        key={i} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="flex items-center justify-between p-3 rounded-xl bg-slate-50 hover:bg-indigo-50 group transition-colors border border-slate-100"
                      >
                        <span className="text-sm font-semibold text-slate-700 truncate max-w-[80%]">{source.title}</span>
                        <ExternalLink className="w-4 h-4 text-slate-400 group-hover:text-indigo-500" />
                      </a>
                    ))}
                  </div>
                </div>
              )}

              <button 
                onClick={reset}
                className="w-full mt-6 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold transition-all shadow-lg shadow-indigo-600/20"
              >
                Scan Another Item
              </button>
            </div>
          </div>
        )}
      </div>

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default ScannerTab;

import React, { useState } from 'react';
import { Camera, Book, Search, MapPin } from 'lucide-react';
import ScannerTab from './components/ScannerTab';
import SurvivalGuideTab from './components/SurvivalGuideTab';
import { Tab } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.SCANNER);

  const renderContent = () => {
    switch (activeTab) {
      case Tab.SCANNER:
        return <ScannerTab />;
      case Tab.GUIDE:
        return <SurvivalGuideTab />;
      default:
        return <ScannerTab />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-white shadow-2xl relative">
      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden">
        {renderContent()}
      </main>

      {/* Bottom Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white/90 backdrop-blur-lg border-t border-slate-200 z-50 flex justify-around items-center h-20 pb-2 px-6">
        <button
          onClick={() => setActiveTab(Tab.SCANNER)}
          className={`flex flex-col items-center justify-center gap-1 transition-all duration-300 w-20 ${
            activeTab === Tab.SCANNER 
              ? 'text-indigo-600 scale-110' 
              : 'text-slate-400 hover:text-slate-600'
          }`}
        >
          <div className={`p-1 rounded-xl ${activeTab === Tab.SCANNER ? 'bg-indigo-50' : ''}`}>
            <Camera className={`w-6 h-6 ${activeTab === Tab.SCANNER ? 'fill-indigo-600/10' : ''}`} />
          </div>
          <span className="text-[10px] font-bold uppercase tracking-wider">Scanner</span>
        </button>

        <button
          onClick={() => setActiveTab(Tab.GUIDE)}
          className={`flex flex-col items-center justify-center gap-1 transition-all duration-300 w-20 ${
            activeTab === Tab.GUIDE 
              ? 'text-indigo-600 scale-110' 
              : 'text-slate-400 hover:text-slate-600'
          }`}
        >
          <div className={`p-1 rounded-xl ${activeTab === Tab.GUIDE ? 'bg-indigo-50' : ''}`}>
            <Book className={`w-6 h-6 ${activeTab === Tab.GUIDE ? 'fill-indigo-600/10' : ''}`} />
          </div>
          <span className="text-[10px] font-bold uppercase tracking-wider">Guide</span>
        </button>
      </nav>

      {/* Status Bar Background Simulation (Aesthetics) */}
      <div className="absolute top-0 left-0 right-0 h-8 bg-gradient-to-b from-black/10 to-transparent pointer-events-none z-30" />
    </div>
  );
};

export default App;

