        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());

        handleIdentify(dataUrl.split(',')[1]);
      }
    }
  };

  const handleIdentify = async (base64: string) => {
    setState(ScanState.IDENTIFYING);
    try {
      const result = await identifyItem(base64);
      setItemName(result.itemName);
      setState(ScanState.CONFIRMING);
    } catch (err) {
      setError("인식에 실패했습니다. 다시 시도해 주세요.");
      setState(ScanState.IDLE);
    }
  };

  const handleConfirm = async () => {
    setState(ScanState.SEARCHING);
    try {
      const result = await getAveragePrice(itemName);
      setPriceData(result);
      setState(ScanState.RESULT);
    } catch (err) {
      setError("가격 정보를 가져오는 데 실패했습니다.");
      setState(ScanState.CONFIRMING);
    }
  };

  const reset = () => {
    setImage(null);
    setItemName('');
    setPriceData(null);
    setError(null);
    setState(ScanState.IDLE);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 overflow-hidden animate-in fade-in duration-500">
      {/* Top Header */}
      <div className="p-4 bg-white/80 backdrop-blur-md border-b border-slate-100 flex justify-between items-center z-30 sticky top-0">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <ScanLine className="w-5 h-5 text-white" />
          </div>
          <h1 className="font-bold text-slate-800 tracking-tight">AI 가격 스캐너</h1>
        </div>
        {state !== ScanState.IDLE && (
          <button onClick={reset} className="p-2 rounded-full hover:bg-slate-100 text-slate-500">
            <RotateCcw className="w-5 h-5" />
          </button>
        )}
      </div>

      <div className="flex-1 relative flex flex-col items-center justify-center p-6 overflow-y-auto pb-24">
        {error && (
          <div className="fixed top-20 left-6 right-6 bg-red-50 text-red-600 p-4 rounded-2xl flex items-center gap-3 z-50 shadow-xl border border-red-100">
            <XCircle className="w-6 h-6 flex-shrink-0" />
            <p className="text-sm font-semibold">{error}</p>
          </div>
        )}

        {state === ScanState.IDLE && (
          <div className="text-center space-y-8 max-w-xs animate-in zoom-in-95 duration-500">
            <div className="relative">
                <div className="w-32 h-32 bg-indigo-600/10 rounded-[2.5rem] flex items-center justify-center mx-auto transform rotate-12"></div>
                <div className="w-32 h-32 bg-indigo-600 rounded-[2.5rem] flex items-center justify-center mx-auto absolute inset-0 shadow-2xl shadow-indigo-600/30">
                    <Camera className="w-14 h-14 text-white" />
                </div>
            </div>
            <div className="space-y-3">
              <h2 className="text-2xl font-bold text-slate-800">바가지 요금 걱정 끝!</h2>
              <p className="text-slate-500 leading-relaxed">달랏 시장에서 궁금한 물건을 찍어보세요. AI가 적정 가격을 알려드립니다.</p>
            </div>
            <button 
              onClick={startCamera}
              className="w-full py-4 bg-slate-900 hover:bg-black text-white rounded-2xl font-bold shadow-xl transition-all active:scale-95"
            >
              스캔 시작하기
            </button>
          </div>
        )}

        {state === ScanState.CAPTURING && (
          <div className="w-full h-full absolute inset-0 bg-black flex flex-col z-20">
            <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-80" />

            {/* Scanner Frame Overlay */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
              <div className="relative w-72 h-72">
                <div className="absolute top-0 left-0 w-8 h-8 border-l-4 border-t-4 border-white rounded-tl-lg"></div>
                <div className="absolute top-0 right-0 w-8 h-8 border-r-4 border-t-4 border-white rounded-tr-lg"></div>
                <div className="absolute bottom-0 left-0 w-8 h-8 border-l-4 border-b-4 border-white rounded-bl-lg"></div>
                <div className="absolute bottom-0 right-0 w-8 h-8 border-r-4 border-b-4 border-white rounded-br-lg"></div>
                <div className="scan-line"></div>
              </div>
            </div>

            <div className="absolute bottom-10 left-0 right-0 flex flex-col items-center gap-6 p-6">
              <p className="text-white font-medium text-sm bg-black/40 px-4 py-2 rounded-full backdrop-blur-md">프레임 안에 물건을 맞춰주세요</p>
              <button 
                onClick={captureImage}
                className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center p-1.5 transition-transform active:scale-90"
              >
                <div className="w-full h-full bg-white rounded-full shadow-inner" />
              </button>
            </div>
          </div>
        )}

        {(state === ScanState.IDENTIFYING || state === ScanState.SEARCHING) && (
          <div className="text-center space-y-8 animate-in fade-in duration-300">
            <div className="relative w-40 h-40 mx-auto">
              <div className="absolute inset-0 bg-indigo-100 rounded-full animate-ping opacity-25"></div>
              <div className="relative w-40 h-40 border-4 border-indigo-600/10 border-t-indigo-600 rounded-full animate-spin flex items-center justify-center">
                <Loader2 className="w-12 h-12 text-indigo-600 animate-pulse" />
              </div>
            </div>
            <div className="space-y-2">
              <p className="text-xl font-bold text-slate-800">
                {state === ScanState.IDENTIFYING ? '어떤 물건인지 분석 중...' : '적정 가격 정보를 찾는 중...'}
              </p>
              <p className="text-sm text-slate-400 font-medium italic">Gemini AI Intelligence</p>
            </div>
          </div>
        )}

        {state === ScanState.CONFIRMING && (
          <div className="w-full space-y-8 max-w-sm animate-in zoom-in-95 duration-500">
            <div className="bg-white rounded-[2.5rem] overflow-hidden shadow-2xl border border-slate-100">
              <img src={image!} alt="Captured item" className="w-full h-72 object-cover" />
              <div className="p-8 text-center bg-white">
                <span className="inline-block px-3 py-1 bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest rounded-full mb-3">AI 인식 결과</span>
                <h3 className="text-3xl font-black text-slate-900 capitalize">{itemName}</h3>
              </div>
            </div>
            <div className="space-y-4">
              <p className="text-center text-slate-500 font-medium">이 품목이 맞나요? 가격 정보를 조회할게요.</p>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={reset}
                  className="py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl font-bold transition-all flex items-center justify-center gap-2"
                >
                  <RotateCcw className="w-5 h-5" />
                  다시 찍기
                </button>
                <button 
                  onClick={handleConfirm}
                  className="py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold shadow-lg shadow-indigo-600/30 transition-all flex items-center justify-center gap-2"
                >
                  <CheckCircle className="w-5 h-5" />
                  조회하기
                </button>
              </div>
            </div>
          </div>
        )}

        {state === ScanState.RESULT && priceData && (
          <div className="w-full space-y-6 max-w-md animate-in slide-in-from-bottom-10 duration-700">
            <div className="bg-white text-slate-900 rounded-[2.5rem] p-8 shadow-2xl relative overflow-hidden border border-slate-100">
              <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-50 rounded-full opacity-50 blur-3xl"></div>

              <div className="flex items-center gap-3 mb-8">
                <div className="bg-indigo-600 p-2.5 rounded-xl text-white shadow-lg shadow-indigo-600/20">
                  <Info className="w-5 h-5" />
                </div>
                <h2 className="text-2xl font-bold text-slate-800 tracking-tight">시장 시세 가이드</h2>
              </div>

              <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 mb-8 shadow-inner">
                <p className="text-slate-700 leading-relaxed font-medium text-lg whitespace-pre-line">
                  {priceData.priceInfo}
                </p>
              </div>

              {priceData.sources.length > 0 && (
                <div className="space-y-4">
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <Search className="w-3 h-3" /> 실시간 근거 자료
                  </p>
                  <div className="space-y-2">
                    {priceData.sources.map((source, i) => (
                      <a 
                        key={i} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="flex items-center justify-between p-4 rounded-2xl bg-white hover:bg-slate-50 transition-all border border-slate-100 group shadow-sm"
                      >
                        <span className="text-sm font-semibold text-slate-700 truncate max-w-[85%]">{source.title}</span>
                        <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-indigo-600 transition-colors" />
                      </a>
                    ))}
                  </div>
                </div>
              )}

              <button 
                onClick={reset}
                className="w-full mt-10 py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-bold transition-all shadow-xl shadow-slate-900/20"
              >
                다른 물건 스캔하기
              </button>
            </div>
          </div>
        )}
      </div>

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default ScannerTab;

