import React, { useState, useRef, useEffect } from 'react';
import { 
  Camera, 
  RotateCcw, 
  CheckCircle, 
  XCircle, 
  Search, 
  Info,
  Loader2,
  ChevronRight,
  ScanLine,
  Sparkles
} from 'lucide-react';
import { identifyItem, getAveragePrice, PriceResult } from '../services/geminiService';

enum ScanState {
  IDLE,
  CAPTURING,
  IDENTIFYING,
  CONFIRMING,
  SEARCHING,
  RESULT
}

const ScannerTab: React.FC = () => {
  const [state, setState] = useState<ScanState>(ScanState.IDLE);
  const [isCameraLoading, setIsCameraLoading] = useState(false);
  const [image, setImage] = useState<string | null>(null);
  const [itemName, setItemName] = useState<string>('');
  const [priceData, setPriceData] = useState<PriceResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // 카메라 스트림 시작 함수
  const startCamera = () => {
    setError(null);
    setState(ScanState.CAPTURING);
    setIsCameraLoading(true);
  };

  // state가 CAPTURING으로 변경되면 실제 카메라 하드웨어에 접근
  useEffect(() => {
    if (state === ScanState.CAPTURING) {
      const initCamera = async () => {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { 
              facingMode: 'environment',
              width: { ideal: 1280 },
              height: { ideal: 720 }
            },
            audio: false
          });

          streamRef.current = stream;

          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.onloadedmetadata = () => {
              setIsCameraLoading(false);
              videoRef.current?.play().catch(console.error);
            };
          }
        } catch (err) {
          console.error("Camera error:", err);
          setError("카메라에 접근할 수 없습니다. 권한 허용 여부를 확인해 주세요.");
          setState(ScanState.IDLE);
          setIsCameraLoading(false);
        }
      };

      initCamera();
    }

    // cleanup: 탭 이동이나 상태 변경 시 카메라 중지
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
      }
    };
  }, [state]);

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        // 실제 비디오 해상도에 맞춰 캔버스 크기 조절
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);

        const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);
        setImage(dataUrl);

        // 카메라 중지
        if (streamRef.current) {
          streamRef.current.getTracks().forEach(track => track.stop());
        }

        handleIdentify(dataUrl.split(',')[1]);
      }
    }
  };

  const handleIdentify = async (base64: string) => {
    setState(ScanState.IDENTIFYING);
    try {
      const result = await identifyItem(base64);
      setItemName(result.itemName);
      setState(ScanState.CONFIRMING);
    } catch (err) {
      setError("AI 분석 중 오류가 발생했습니다. 다시 시도해 주세요.");
      setState(ScanState.IDLE);
    }
  };

  const handleConfirm = async () => {
    setState(ScanState.SEARCHING);
    try {
      const result = await getAveragePrice(itemName);
      setPriceData(result);
      setState(ScanState.RESULT);
    } catch (err) {
      setError("가격 정보를 가져오는 데 실패했습니다.");
      setState(ScanState.CONFIRMING);
    }
  };

  const reset = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    setImage(null);
    setItemName('');
    setPriceData(null);
    setError(null);
    setIsCameraLoading(false);
    setState(ScanState.IDLE);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 overflow-hidden animate-in fade-in duration-500">
      {/* Header */}
      <div className="p-4 bg-white/90 backdrop-blur-md border-b border-slate-100 flex justify-between items-center z-40 sticky top-0">
        <div className="flex items-center gap-2">
          <div className="w-9 h-9 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-200">
            <ScanLine className="w-5 h-5 text-white" />
          </div>
          <h1 className="font-bold text-slate-800 tracking-tight text-lg">AI 가격 스캐너</h1>
        </div>
        {state !== ScanState.IDLE && (
          <button 
            onClick={reset} 
            className="p-2.5 rounded-full hover:bg-slate-100 text-slate-500 transition-colors"
            aria-label="초기화"
          >
            <RotateCcw className="w-5 h-5" />
          </button>
        )}
      </div>

      <div className="flex-1 relative flex flex-col items-center justify-center p-6 overflow-y-auto pb-24">
        {error && (
          <div className="fixed top-24 left-6 right-6 bg-white text-red-600 p-5 rounded-3xl flex items-center gap-4 z-[60] shadow-2xl border border-red-100 animate-in slide-in-from-top-4 duration-300">
            <div className="w-10 h-10 bg-red-50 rounded-full flex items-center justify-center flex-shrink-0">
              <XCircle className="w-6 h-6" />
            </div>
            <p className="text-sm font-bold leading-tight">{error}</p>
          </div>
        )}

        {state === ScanState.IDLE && (
          <div className="text-center space-y-10 max-w-xs animate-in zoom-in-95 duration-500">
            <div className="relative">
                <div className="w-32 h-32 bg-indigo-600/10 rounded-[2.5rem] flex items-center justify-center mx-auto transform rotate-12 animate-pulse"></div>
                <div className="w-32 h-32 bg-indigo-600 rounded-[3rem] flex items-center justify-center mx-auto absolute inset-0 shadow-2xl shadow-indigo-600/40">
                    <Camera className="w-14 h-14 text-white" />
                </div>
                <div className="absolute -top-2 -right-2 bg-yellow-400 p-2 rounded-2xl shadow-lg transform -rotate-12">
                   <Sparkles className="w-5 h-5 text-indigo-900 fill-indigo-900/20" />
                </div>
            </div>
            <div className="space-y-4">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">바가지 요금,<br/>이제 찍어서 확인!</h2>
