import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface IdentificationResult {
  itemName: string;
}

export interface PriceResult {
  priceRange: string;
  unit: string;
  negotiationTip: string;
  description: string;
  sources: { title: string; uri: string }[];
}

export const identifyItem = async (base64Image: string): Promise<IdentificationResult> => {
  const ai = getAIClient();
  const prompt = "당신은 베트남 달랏 야시장의 전문가 가이드입니다. 이 이미지 속의 주요 음식이나 기념품이 무엇인지 한국어로 답변하세요. 오직 상품 이름만 짧게 답변하세요.";

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: prompt }
      ]
    }
  });

  return { itemName: response.text?.trim() || '알 수 없는 품목' };
};

export const getAveragePrice = async (itemName: string): Promise<PriceResult> => {
  const ai = getAIClient();
  const prompt = `베트남 달랏 현지 시장에서 "${itemName}"의 현재 평균 가격 정보를 알려주세요. 
  반드시 다음 JSON 형식으로만 답변하세요:
  {
    "priceRange": "예: 20,000 - 30,000",
    "unit": "예: 1kg당 또는 1개당",
    "negotiationTip": "흥정할 때 유용한 팁 한 줄",
    "description": "이 물건에 대한 간단한 특징이나 고르는 법 (한국어)"
  }`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json"
    }
  });

  let data;
  try {
    data = JSON.parse(response.text || '{}');
  } catch (e) {
    data = {
      priceRange: "가격 정보 확인 중",
      unit: "-",
      negotiationTip: "현지 상황에 따라 다를 수 있습니다.",
      description: response.text || "상세 설명을 가져오지 못했습니다."
    };
  }

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || '참고 자료',
    uri: chunk.web?.uri || '#'
  })) || [];

  return {
    ...data,
    sources
  };
};

