import React, { useState } from 'react';
import { MessageCircle, Volume2, Sparkles, Star, Send, Loader2, Languages, Play } from 'lucide-react';
import { PHRASES, TRANSLATIONS } from '../constants';
import { Language } from '../types';
import { translateText, TranslationResult, generateSpeech } from '../services/geminiService';

interface Props { lang: Language; }

const PhrasesTab: React.FC<Props> = ({ lang }) => {
  const [inputText, setInputText] = useState('');
  const [translation, setTranslation] = useState<TranslationResult | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const t = TRANSLATIONS[lang];

  const handleTranslate = async () => {
    if (!inputText.trim()) return;
    setIsTranslating(true);
    try {
      const result = await translateText(inputText, lang);
      setTranslation(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsTranslating(false);
    }
  };

  const playTTS = async (text: string, id: string) => {
    if (playingId) return;
    setPlayingId(id);
    try {
      // Gemini 2.5 TTS 모델로부터 Base64 오디오 데이터 가져오기
      const base64Audio = await generateSpeech(text, 'Puck');

      const byteCharacters = atob(base64Audio);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i);
      }
      const byteArray = new Uint8Array(byteNumbers);

      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const arrayBuffer = byteArray.buffer;

      // Raw PCM Decoding (16-bit Mono, 24kHz)
      const dataInt16 = new Int16Array(arrayBuffer);
      const audioBuffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = audioBuffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }

      const source = audioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContext.destination);
      source.onended = () => {
        setPlayingId(null);
        audioContext.close();
      };
      source.start();

    } catch (e) {
      console.error("TTS 재생 실패:", e);
      setPlayingId(null);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 animate-in fade-in">
      {/* Header with Translation Input */}
      <div className="px-6 pt-12 pb-8 bg-white border-b border-slate-100 sticky top-0 z-10 rounded-b-[2.5rem] shadow-sm">
        <div className="flex items-center justify-between mb-6">
          <div className="space-y-1">
            <div className="flex items-center gap-2 text-indigo-600">
              <Sparkles className="w-4 h-4 fill-indigo-600" />
              <span className="text-[10px] font-black uppercase tracking-[0.2em]">Translator</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tighter">{t.phrasesTitle}</h1>
          </div>
          <div className="p-3 bg-indigo-50 rounded-2xl text-indigo-600"><Languages /></div>
        </div>

        {/* Text Translator Input */}
        <div className="relative group">
          <input 
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleTranslate()}
            placeholder={t.translatePlaceholder}
            className="w-full p-5 pr-14 bg-slate-50 border border-slate-100 rounded-3xl font-bold text-slate-800 outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-inner"
          />
          <button 
            onClick={handleTranslate}
            disabled={isTranslating || !inputText}
            className="absolute right-2 top-2 p-3 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white rounded-2xl transition-all shadow-lg active:scale-90"
          >
            {isTranslating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>

        {/* Translation Result Card */}
        {translation && (
          <div className="mt-4 p-6 bg-indigo-600 rounded-[2rem] text-white animate-in slide-in-from-top-4 shadow-xl shadow-indigo-200">
            <div className="flex justify-between items-start">
              <div className="space-y-2">
                <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">번역 결과</p>
                <h3 className="text-2xl font-black tracking-tight leading-tight">{translation.translatedText}</h3>
                {translation.phonetic && (
                  <p className="text-indigo-100/70 text-sm font-medium italic">"{translation.phonetic}"</p>
                )}
              </div>
              <button 
                onClick={() => playTTS(translation.translatedText, 'result')}
                disabled={playingId === 'result'}
                className={`p-4 rounded-2xl transition-all ${playingId === 'result' ? 'bg-indigo-400 opacity-50' : 'bg-white/20 hover:bg-white/30 active:scale-90'}`}
              >
                {playingId === 'result' ? <Loader2 className="w-5 h-5 animate-spin text-white" /> : <Volume2 className="w-5 h-5 text-white" />}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Preset Phrase List */}
      <div className="flex-1 p-6 space-y-4 overflow-y-auto pb-32">
        <div className="flex items-center gap-2 px-2">
          <MessageCircle className="w-4 h-4 text-slate-400" />
          <span className="text-xs font-black text-slate-400 uppercase tracking-widest">필수 회화</span>
        </div>

        {PHRASES.map((p) => (
          <div key={p.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center justify-between group active:scale-98 transition-all">
            <div className="space-y-1">
              <span className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded-full">{p.category}</span>
              <h3 className="text-lg font-black text-slate-900">{p.ko}</h3>
              <p className="text-indigo-600 font-black text-xl tracking-tight">{p.vn}</p>
              <p className="text-slate-400 text-sm italic font-medium">"{p.phonetic}"</p>
            </div>
            <button 
              onClick={() => playTTS(p.vn, p.id)}
              disabled={playingId === p.id}
              className={`p-4 rounded-2xl transition-all ${
                playingId === p.id 
                  ? 'bg-indigo-600 text-white animate-pulse' 
                  : 'bg-slate-50 text-slate-400 group-hover:bg-indigo-600 group-hover:text-white'
              }`}
            >
              {playingId === p.id ? <Loader2 className="w-6 h-6 animate-spin" /> : <Volume2 className="w-6 h-6" />}
            </button>
          </div>
        ))}

        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white space-y-4 relative overflow-hidden shadow-2xl">
          <Star className="absolute -top-4 -right-4 w-24 h-24 text-white/5 rotate-12" />
          <h4 className="font-black text-lg">💡 작은 팁</h4>
          <p className="text-slate-400 text-sm leading-relaxed font-medium">
            베트남어는 성조가 생명이지만, 시장 상인들은 외국인들의 발음에 매우 관대합니다. AI 음성을 잘 듣고 비슷하게 흉내만 내보세요!
          </p>
        </div>
      </div>
    </div>
  );
};

export default PhrasesTab;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Camera, RotateCcw, CheckCircle, XCircle, Search, Info, Loader2,
  ChevronRight, ScanLine, Sparkles, Tag, Lightbulb, ExternalLink,
  Keyboard, Edit3, X
} from 'lucide-react';
import { identifyItem, getAveragePrice, PriceResult } from '../services/geminiService';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

enum ScanState { IDLE, CAPTURING, IDENTIFYING, CONFIRMING, SEARCHING, RESULT, MANUAL_INPUT }

interface Props { lang: Language; }

const ScannerTab: React.FC<Props> = ({ lang }) => {
  const [state, setState] = useState<ScanState>(ScanState.IDLE);
  const [isCameraLoading, setIsCameraLoading] = useState(false);
  const [image, setImage] = useState<string | null>(null);
  const [itemName, setItemName] = useState<string>('');
  const [priceData, setPriceData] = useState<PriceResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const t = TRANSLATIONS[lang];

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const initCamera = async () => {
    setIsCameraLoading(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.onloadedmetadata = () => {
          setIsCameraLoading(false);
          videoRef.current?.play().catch(console.error);
        };
      }
    } catch (err) {
      setError(t.identifyFailed);
      setState(ScanState.IDLE);
    }
  };

  useEffect(() => {
    if (state === ScanState.CAPTURING) initCamera();
    return () => {
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    };
  }, [state]);

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);
        setImage(dataUrl);
        if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
        handleIdentify(dataUrl.split(',')[1]);
      }
    }
  };

  const handleIdentify = async (base64: string) => {
    setState(ScanState.IDENTIFYING);
    try {
      const result = await identifyItem(base64, lang);
      setItemName(result.itemName);
      setState(ScanState.CONFIRMING);
    } catch (err) {
      setError(t.identifyFailed);
      setState(ScanState.IDLE);
    }
  };

  const handlePriceSearch = async () => {
    if (!itemName.trim()) return;
    setState(ScanState.SEARCHING);
    try {
      const result = await getAveragePrice(itemName, lang);
      setPriceData(result);
      setState(ScanState.RESULT);
    } catch (err) {
      setError(t.priceFailed);
      setState(ScanState.CONFIRMING);
    }
  };

  const reset = () => {
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    setImage(null); setItemName(''); setPriceData(null); setError(null); setState(ScanState.IDLE);
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 overflow-hidden">
      <div className="p-4 bg-white/90 backdrop-blur-md border-b border-slate-100 flex justify-between items-center z-40 sticky top-0">
        <div className="flex items-center gap-2">
          <ScanLine className="w-6 h-6 text-indigo-600" />
          <h1 className="font-bold text-slate-800">{t.scannerTitle}</h1>
        </div>
        {state !== ScanState.IDLE && <button onClick={reset} className="p-2 rounded-full hover:bg-slate-100 text-slate-500"><RotateCcw className="w-5 h-5" /></button>}
      </div>

      <div className="flex-1 relative p-6 overflow-y-auto pb-32">
        {state === ScanState.IDLE && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-10 animate-in zoom-in-95">
            <div className="space-y-2">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">{t.startTitle}</h2>
              <p className="text-slate-500 font-medium">{t.startSub}</p>
            </div>
            <div className="w-full space-y-4">
              <button onClick={() => setState(ScanState.CAPTURING)} className="w-full p-8 bg-indigo-600 rounded-[2rem] flex items-center justify-between group shadow-xl shadow-indigo-200">
                <div className="flex items-center gap-5">
                  <div className="bg-white/20 p-4 rounded-2xl text-white"><Camera className="w-8 h-8" /></div>
                  <span className="text-xl font-bold text-white">{t.byCamera}</span>
                </div>
                <ChevronRight className="w-6 h-6 text-white opacity-50 group-hover:translate-x-1 transition-transform" />
              </button>
              <button onClick={() => setState(ScanState.MANUAL_INPUT)} className="w-full p-8 bg-white border border-slate-200 rounded-[2rem] flex items-center justify-between group">
                <div className="flex items-center gap-5">
                  <div className="bg-slate-100 p-4 rounded-2xl text-slate-600"><Keyboard className="w-8 h-8" /></div>
                  <span className="text-xl font-bold text-slate-800">{t.bySearch}</span>
                </div>
                <ChevronRight className="w-6 h-6 text-slate-300 group-hover:translate-x-1 transition-transform" />
              </button>
            </div>
          </div>
        )}

        {state === ScanState.CAPTURING && (
          <div className="fixed inset-0 bg-black z-[100] flex flex-col h-[100dvh] overflow-hidden">
            {/* Top Controls */}
            <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-[110] pt-[env(safe-area-inset-top,24px)]">
              <button 
                onClick={reset}
                className="p-4 bg-black/40 backdrop-blur-md rounded-full text-white hover:bg-black/60 transition-colors active:scale-90"
              >
                <X className="w-7 h-7" />
              </button>
              <div className="bg-indigo-600 px-4 py-1.5 rounded-full text-white text-[10px] font-bold uppercase tracking-widest shadow-lg">
                Scanning...
              </div>
            </div>

            {/* Camera View */}
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              className="flex-1 object-cover w-full h-full"
            />

            {/* Overlay Grid */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
              <div className="w-64 h-64 border-2 border-white/20 rounded-3xl relative">
                <div className="scan-line" />
                <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-white rounded-tl-xl" />
                <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-white rounded-tr-xl" />
                <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-white rounded-bl-xl" />
                <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-white rounded-br-xl" />
              </div>
            </div>

            {isCameraLoading && (
              <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-md flex flex-col items-center justify-center text-white z-[120]">
                <Loader2 className="w-10 h-10 animate-spin text-indigo-400 mb-4" />
                <p className="font-bold text-slate-300 uppercase tracking-widest text-xs">Initializing Camera...</p>
              </div>
            )}

            {/* Bottom Capture Area - 어떤 기종에서도 보이도록 safe area padding 적용 */}
            <div className="absolute bottom-0 left-0 right-0 p-12 pb-[calc(2rem+env(safe-area-inset-bottom,64px))] flex justify-center bg-gradient-to-t from-black/90 via-black/40 to-transparent z-[110]">
              <button 
                onClick={captureImage} 
                className="w-24 h-24 rounded-full border-[6px] border-white/30 p-1.5 active:scale-95 transition-transform shadow-[0_0_50px_rgba(255,255,255,0.2)]"
              >
                <div className="w-full h-full bg-white rounded-full flex items-center justify-center shadow-inner">
                  <Camera className="w-10 h-10 text-slate-900" />
                </div>
              </button>
            </div>
          </div>
        )}

        {state === ScanState.MANUAL_INPUT && (
          <div className="h-full flex flex-col items-center pt-20 space-y-8 animate-in slide-in-from-bottom-5">
            <div className="bg-indigo-600/10 p-6 rounded-[2.5rem]"><Search className="w-12 h-12 text-indigo-600" /></div>
            <div className="w-full space-y-6">
              <input 
                type="text" 
