import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { Language } from '../types';

export interface IdentificationResult {
  itemName: string;
}

export interface PriceResult {
  priceRange: string;
  unit: string;
  negotiationTip: string;
  description: string;
  sources: { title: string; uri: string }[];
}

export interface TranslationResult {
  translatedText: string;
  phonetic: string;
}

export const identifyItem = async (base64Image: string, lang: Language): Promise<IdentificationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const langText = lang === 'KO' ? '한국어' : 'Tiếng Việt';
  const prompt = `당신은 베트남 달랏 야시장의 전문가 가이드입니다. 이 이미지 속의 주요 음식이나 기념품이 무엇인지 ${langText}로 답변하세요. 오직 상품 이름만 짧게 답변하세요.`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: prompt }
      ]
    }
  });

  return { itemName: response.text?.trim() || (lang === 'KO' ? '알 수 없음' : 'Không xác định') };
};

export const getAveragePrice = async (itemName: string, lang: Language): Promise<PriceResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const langText = lang === 'KO' ? '한국어' : 'Tiếng Việt';
  const prompt = `Provide the current average price for "${itemName}" in Dalat Market. 
  Answer in ${langText}.
  Return ONLY a JSON object:
  {
    "priceRange": "string (e.g., 20.000 - 30.000)",
    "unit": "string (e.g., per 1kg)",
    "negotiationTip": "one sentence bargaining tip",
    "description": "brief description or how to pick a good one"
  }`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json"
    }
  });

  let data;
  try {
    data = JSON.parse(response.text || '{}');
  } catch (e) {
    data = {
      priceRange: "-",
      unit: "-",
      negotiationTip: lang === 'KO' ? "흥정이 필요합니다." : "Cần trả giá.",
      description: response.text || ""
    };
  }

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || 'Ref',
    uri: chunk.web?.uri || '#'
  })) || [];

  return { ...data, sources };
};

export const translateText = async (text: string, sourceLang: Language): Promise<TranslationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const targetLang = sourceLang === 'KO' ? 'Vietnamese' : 'Korean';

  const prompt = `Translate the following text into ${targetLang}. 
  If translating to Vietnamese, also provide a simplified Korean pronunciation (phonetic) for it.
  Return ONLY a JSON object:
  {
    "translatedText": "translated string",
    "phonetic": "phonetic reading in source language's alphabet (empty if not applicable)"
  }
  Text: "${text}"`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json"
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    return { translatedText: text, phonetic: "" };
  }
};

export const generateSpeech = async (text: string, voiceName: 'Kore' | 'Puck' | 'Zephyr' | 'Charon' | 'Fenrir' = 'Puck'): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    // 군더더기 없는 발음을 위해 텍스트만 전달
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts[0]?.inlineData?.data;
    if (!base64Audio) {
      throw new Error("API로부터 오디오 데이터를 받지 못했습니다.");
    }
    return base64Audio;
  } catch (error: any) {
    console.error("Gemini TTS Error:", error);
    throw new Error(error.message || "음성 생성 실패");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, Volume2, Sparkles, Star, Send, Loader2, Languages, Play, AlertCircle } from 'lucide-react';
import { PHRASES, TRANSLATIONS } from '../constants';
import { Language } from '../types';
import { translateText, TranslationResult, generateSpeech } from '../services/geminiService';

interface Props { lang: Language; }

const PhrasesTab: React.FC<Props> = ({ lang }) => {
  const [inputText, setInputText] = useState('');
  const [translation, setTranslation] = useState<TranslationResult | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const t = TRANSLATIONS[lang];

  // 오디오 리소스 관리를 위한 ref
  const audioContextRef = useRef<AudioContext | null>(null);

  // 컴포넌트 언마운트 시 오디오 컨텍스트 정리
  useEffect(() => {
    return () => {
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, []);

  const handleTranslate = async () => {
    if (!inputText.trim()) return;
    setIsTranslating(true);
    setError(null);
    try {
      const result = await translateText(inputText, lang);
      setTranslation(result);
    } catch (e: any) {
      setError("번역 실패: " + (e.message || "네트워크 오류"));
    } finally {
      setIsTranslating(false);
    }
  };

  // 가이드라인에 따른 수동 디코딩 함수
  function decode(base64: string) {
    // 공백 및 줄바꿈 제거 (atob 오류 방지)
    const cleanedBase64 = base64.replace(/\s/g, '');
    const binaryString = window.atob(cleanedBase64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer, 0, Math.floor(data.byteLength / 2));
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        // 16-bit PCM 정규화
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  }

  const playTTS = async (text: string, id: string) => {
    if (playingId) return;
    setPlayingId(id);
    setError(null);

    try {
      // 1. AudioContext 상태 확인 및 초기화
      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      const ctx = audioContextRef.current;

      // 2. API로부터 음성 데이터 수신
      const base64Audio = await generateSpeech(text, 'Puck');

      // 3. 데이터 디코딩
      const decodedData = decode(base64Audio);
      const audioBuffer = await decodeAudioData(decodedData, ctx, 24000, 1);

      // 4. 즉시 재생
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setPlayingId(null);
      source.start(0);

    } catch (e: any) {
      console.error("TTS Playback Error:", e);
      setError("음성 재생 실패: " + (e.message || "다시 시도해주세요"));
      setPlayingId(null);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 animate-in fade-in">
      {/* Header & Translator */}
      <div className="px-6 pt-12 pb-8 bg-white border-b border-slate-100 sticky top-0 z-10 rounded-b-[2.5rem] shadow-sm">
        <div className="flex items-center justify-between mb-6">
          <div className="space-y-1">
            <div className="flex items-center gap-2 text-indigo-600">
              <Sparkles className="w-4 h-4 fill-indigo-600" />
              <span className="text-[10px] font-black uppercase tracking-[0.2em]">Translator</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tighter">{t.phrasesTitle}</h1>
          </div>
          <div className="p-3 bg-indigo-50 rounded-2xl text-indigo-600"><Languages /></div>
        </div>

        <div className="relative group">
          <input 
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleTranslate()}
            placeholder={t.translatePlaceholder}
            className="w-full p-5 pr-14 bg-slate-50 border border-slate-100 rounded-3xl font-bold text-slate-800 outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-inner"
          />
          <button 
            onClick={handleTranslate}
            disabled={isTranslating || !inputText}
            className="absolute right-2 top-2 p-3 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white rounded-2xl transition-all shadow-lg active:scale-90"
          >
            {isTranslating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>

        {error && (
          <div className="mt-4 flex items-center gap-2 text-rose-600 text-[11px] font-bold px-4 py-2 bg-rose-50 rounded-xl border border-rose-100 animate-in slide-in-from-top-1">
            <AlertCircle className="w-3.5 h-3.5 flex-shrink-0" />
            <span className="line-clamp-1">{error}</span>
          </div>
        )}

        {translation && (
          <div className="mt-4 p-6 bg-indigo-600 rounded-[2rem] text-white animate-in slide-in-from-top-4 shadow-xl shadow-indigo-200">
            <div className="flex justify-between items-start">
              <div className="space-y-2 flex-1 pr-4">
                <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">번역 결과</p>
                <h3 className="text-2xl font-black tracking-tight leading-tight break-words">{translation.translatedText}</h3>
                {translation.phonetic && (
                  <p className="text-indigo-100/70 text-sm font-medium italic">"{translation.phonetic}"</p>
                )}
              </div>
              <button 
                onClick={() => playTTS(translation.translatedText, 'result')}
                disabled={playingId === 'result'}
                className={`p-4 rounded-2xl transition-all flex-shrink-0 ${playingId === 'result' ? 'bg-indigo-400 cursor-wait' : 'bg-white/20 hover:bg-white/30 active:scale-90'}`}
              >
                {playingId === 'result' ? <Loader2 className="w-5 h-5 animate-spin text-white" /> : <Volume2 className="w-5 h-5 text-white" />}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Phrase List */}
      <div className="flex-1 p-6 space-y-4 overflow-y-auto pb-40">
        <div className="flex items-center gap-2 px-2">
          <MessageCircle className="w-4 h-4 text-slate-400" />
          <span className="text-xs font-black text-slate-400 uppercase tracking-widest">필수 회화</span>
        </div>

        {PHRASES.map((p) => (
          <div key={p.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center justify-between group active:scale-98 transition-all">
            <div className="space-y-1">
              <span className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded-full">{p.category}</span>
              <h3 className="text-lg font-black text-slate-900">{p.ko}</h3>
              <p className="text-indigo-600 font-black text-xl tracking-tight">{p.vn}</p>
              <p className="text-slate-400 text-sm italic font-medium">"{p.phonetic}"</p>
            </div>
            <button 
              onClick={() => playTTS(p.vn, p.id)}
              disabled={playingId === p.id}
              className={`p-4 rounded-2xl transition-all flex-shrink-0 ${
                playingId === p.id 
                  ? 'bg-indigo-600 text-white shadow-inner cursor-wait' 
                  : 'bg-slate-50 text-slate-400 group-hover:bg-indigo-600 group-hover:text-white'
              }`}
            >
              {playingId === p.id ? <Loader2 className="w-6 h-6 animate-spin" /> : <Volume2 className="w-6 h-6" />}
            </button>
          </div>
        ))}

        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white space-y-4 relative overflow-hidden shadow-2xl">
          <Star className="absolute -top-4 -right-4 w-24 h-24 text-white/5 rotate-12" />
          <h4 className="font-black text-lg">💡 작은 팁</h4>
          <p className="text-slate-400 text-sm leading-relaxed font-medium">
            베트남어는 성조가 중요하지만, 상인들은 외국인의 노력에 호의적입니다. AI 음성의 억양을 최대한 비슷하게 따라해 보세요!
          </p>
        </div>
      </div>
    </div>
  );
};

