import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { Language } from '../types';

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface IdentificationResult {
  itemName: string;
}

export interface PriceResult {
  priceRange: string;
  unit: string;
  negotiationTip: string;
  description: string;
  sources: { title: string; uri: string }[];
}

export interface TranslationResult {
  translatedText: string;
  phonetic: string;
}

export const identifyItem = async (base64Image: string, lang: Language): Promise<IdentificationResult> => {
  const ai = getAI();
  const langText = lang === 'KO' ? '한국어' : 'Tiếng Việt';
  const prompt = `당신은 베트남 달랏 야시장의 전문가 가이드입니다. 이 이미지 속의 주요 음식이나 기념품이 무엇인지 ${langText}로 답변하세요. 오직 상품 이름만 짧게 답변하세요.`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: prompt }
      ]
    }
  });

  return { itemName: response.text?.trim() || (lang === 'KO' ? '알 수 없음' : 'Không xác định') };
};

export const getAveragePrice = async (itemName: string, lang: Language): Promise<PriceResult> => {
  const ai = getAI();
  const langText = lang === 'KO' ? '한국어' : 'Tiếng Việt';

  const prompt = `Provide current market price info for "${itemName}" in Dalat Night Market (Dalat, Vietnam).
  Language: ${langText}.

  Please provide the info in this exact format:
  PRICE: [range in VND]
  UNIT: [e.g. per kg, per piece]
  TIP: [one bargaining tip]
  DESC: [brief description]`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const text = response.text || "";
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || 'Ref',
    uri: chunk.web?.uri || '#'
  })) || [];

  const priceMatch = text.match(/PRICE:\s*(.*)/i);
  const unitMatch = text.match(/UNIT:\s*(.*)/i);
  const tipMatch = text.match(/TIP:\s*(.*)/i);
  const descMatch = text.match(/DESC:\s*(.*)/i);

  return {
    priceRange: priceMatch ? priceMatch[1].trim() : "시세 확인 중",
    unit: unitMatch ? unitMatch[1].trim() : "단위 미정",
    negotiationTip: tipMatch ? tipMatch[1].trim() : (lang === 'KO' ? "흥정이 필요합니다." : "Cần trả giá."),
    description: descMatch ? descMatch[1].trim() : text.substring(0, 100),
    sources
  };
};

export const translateText = async (text: string, sourceLang: Language): Promise<TranslationResult> => {
  const ai = getAI();
  const targetLang = sourceLang === 'KO' ? 'Vietnamese' : 'Korean';

  const prompt = `Translate to ${targetLang}. 
  If Vietnamese, include phonetic Korean pronunciation.
  Return JSON: {"translatedText": "...", "phonetic": "..."}
  Text: "${text}"`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json"
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    return { translatedText: text, phonetic: "" };
  }
};

export const generateSpeech = async (text: string, voiceName: 'Kore' | 'Puck' | 'Zephyr' | 'Charon' | 'Fenrir' = 'Puck'): Promise<string> => {
  try {
    const ai = getAI();
    // TTS를 위한 텍스트 전처리 (불필요한 공백 및 문장 부호 제거)
    const cleanText = text.trim();
    if (!cleanText) throw new Error("Text is empty");

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: cleanText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) {
      throw new Error("No audio data returned from API");
    }
    return base64Audio;
  } catch (error: any) {
    console.error("Gemini TTS Service Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, Volume2, Sparkles, Star, Send, Loader2, Languages, Play, AlertCircle, Key } from 'lucide-react';
import { PHRASES, TRANSLATIONS } from '../constants';
import { Language } from '../types';
import { translateText, TranslationResult, generateSpeech } from '../services/geminiService';

interface Props { lang: Language; }

const PhrasesTab: React.FC<Props> = ({ lang }) => {
  const [inputText, setInputText] = useState('');
  const [translation, setTranslation] = useState<TranslationResult | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const t = TRANSLATIONS[lang];

  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    return () => {
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, []);

  const handleTranslate = async () => {
    if (!inputText.trim()) return;
    setIsTranslating(true);
    setError(null);
    try {
      const result = await translateText(inputText, lang);
      setTranslation(result);
    } catch (e: any) {
      handleApiError(e, "번역 실패");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleApiError = async (e: any, defaultMsg: string) => {
    const errorMsg = e.message || "";
    console.error("API Error Detail:", e);

    if (errorMsg.includes("Requested entity was not found") || 
        errorMsg.includes("API_KEY") || 
        errorMsg.includes("403") || 
        errorMsg.includes("404")) {
      setError("API 권한 또는 키 설정이 필요합니다.");
      if (window.aistudio) {
        setTimeout(() => window.aistudio.openSelectKey(), 500);
      }
    } else {
      setError(`${defaultMsg}: 다시 시도해주세요.`);
    }
  };

  function decodeBase64ToUint8Array(base64: string) {
    const cleanedBase64 = base64.replace(/\s/g, '');
    try {
      const binaryString = window.atob(cleanedBase64);
      const bytes = new Uint8Array(binaryString.length);
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      return bytes;
    } catch (e) {
      throw new Error("Base64 decoding failed");
    }
  }

  async function decodeRawPcmToAudioBuffer(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> {
    // 바이트 정렬 문제를 피하기 위해 DataView 사용
    const byteLength = data.byteLength;
    const numSamples = Math.floor(byteLength / 2); // 16-bit PCM = 2 bytes per sample
    const frameCount = numSamples / numChannels;
    const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    const dataView = new DataView(data.buffer, data.byteOffset, byteLength);

    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = audioBuffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        const byteIndex = (i * numChannels + channel) * 2;
        // Gemini API는 리틀 엔디안(Little Endian) PCM을 반환할 가능성이 높음
        if (byteIndex + 1 < byteLength) {
          const sample = dataView.getInt16(byteIndex, true);
          channelData[i] = sample / 32768.0;
        }
      }
    }
    return audioBuffer;
  }

  const playTTS = async (text: string, id: string) => {
    if (playingId) return;
    setPlayingId(id);
    setError(null);

    try {
      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      // 텍스트 정제 (문장 부호 제거하여 TTS 엔진 호환성 향상)
      const cleanText = text.replace(/[!?,.]/g, '').trim();
      const base64Audio = await generateSpeech(cleanText, 'Puck');

      const uint8Data = decodeBase64ToUint8Array(base64Audio);
      const audioBuffer = await decodeRawPcmToAudioBuffer(uint8Data, ctx, 24000, 1);

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setPlayingId(null);
      source.start(0);

    } catch (e: any) {
      handleApiError(e, "음성 재생 실패");
      setPlayingId(null);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 animate-in fade-in">
      <div className="px-6 pt-16 pb-8 bg-white border-b border-slate-100 sticky top-0 z-10 rounded-b-[2.5rem] shadow-sm">
        <div className="flex items-center justify-between mb-6">
          <div className="space-y-1">
            <div className="flex items-center gap-2 text-indigo-600">
              <Sparkles className="w-4 h-4 fill-indigo-600" />
              <span className="text-[10px] font-black uppercase tracking-[0.2em]">Translator</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tighter">{t.phrasesTitle}</h1>
          </div>
          <div className="p-3 bg-indigo-50 rounded-2xl text-indigo-600"><Languages /></div>
        </div>

        <div className="relative group">
          <input 
            type="text" 
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleTranslate()}
            placeholder={t.translatePlaceholder}
            className="w-full p-5 pr-14 bg-slate-50 border border-slate-100 rounded-3xl font-bold text-slate-800 outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-inner"
          />
          <button 
            onClick={handleTranslate}
            disabled={isTranslating || !inputText}
            className="absolute right-2 top-2 p-3 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white rounded-2xl transition-all shadow-lg active:scale-90"
          >
            {isTranslating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>

        {error && (
          <div className="mt-4 flex items-center justify-between gap-2 text-rose-600 text-[11px] font-bold px-4 py-2 bg-rose-50 rounded-xl border border-rose-100 animate-in slide-in-from-top-1">
            <div className="flex items-center gap-2">
              <AlertCircle className="w-3.5 h-3.5 flex-shrink-0" />
              <span className="line-clamp-1">{error}</span>
            </div>
            <button onClick={() => window.aistudio?.openSelectKey()} className="text-rose-700 underline flex items-center gap-1 shrink-0">
              <Key className="w-3 h-3" /> 키 재설정
            </button>
          </div>
        )}

        {translation && (
          <div className="mt-4 p-6 bg-indigo-600 rounded-[2rem] text-white animate-in slide-in-from-top-4 shadow-xl shadow-indigo-200">
            <div className="flex justify-between items-start">
              <div className="space-y-2 flex-1 pr-4">
                <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">번역 결과</p>
                <h3 className="text-2xl font-black tracking-tight leading-tight break-words">{translation.translatedText}</h3>
                {translation.phonetic && (
                  <p className="text-indigo-100/70 text-sm font-medium italic">"{translation.phonetic}"</p>
                )}
              </div>
              <button 
                onClick={() => playTTS(translation.translatedText, 'result')}
                disabled={playingId === 'result'}
