                       </a>
                     ))}
                   </div>
                </div>
              )}
            </div>

            <button onClick={reset} className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black text-xl shadow-2xl hover:bg-slate-800 active:scale-95 transition-all mb-8">{t.reset}</button>
          </div>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

