            <div className="w-full space-y-4">
              <button onClick={() => setState(ScanState.CAPTURING)} className="w-full p-8 bg-indigo-600 rounded-[2.5rem] flex items-center justify-between group shadow-xl shadow-indigo-200 active:scale-95 transition-all">
                <div className="flex items-center gap-5">
                  <div className="bg-white/20 p-4 rounded-2xl text-white"><Camera className="w-8 h-8" /></div>
                  <span className="text-2xl font-black text-white tracking-tight">{t.byCamera}</span>
