              <button onClick={() => setState(ScanState.MANUAL_INPUT)} className="w-full p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] flex items-center justify-between group active:scale-95 transition-all">
                <div className="flex items-center gap-5">
                  <div className="bg-slate-50 p-4 rounded-2xl text-slate-400"><Keyboard className="w-8 h-8" /></div>
                  <span className="text-2xl font-black text-slate-800 tracking-tight">{t.bySearch}</span>
                </div>
                <ChevronRight className="w-6 h-6 text-slate-300" />
              </button>
            </div>
          </div>
        )}

        {state === ScanState.CAPTURING && (
          <div className="fixed inset-0 bg-black z-[100] flex flex-col h-[100dvh]">
            <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-[110] pt-[env(safe-area-inset-top,24px)]">
              <button onClick={reset} className="p-4 bg-black/40 backdrop-blur-md rounded-full text-white"><X className="w-7 h-7" /></button>
            </div>
            <video ref={videoRef} autoPlay playsInline muted className="flex-1 object-cover w-full h-full" />
            <div className="absolute bottom-0 left-0 right-0 p-12 pb-[calc(2rem+env(safe-area-inset-bottom,64px))] flex justify-center bg-gradient-to-t from-black/90 to-transparent">
              <button onClick={captureImage} className="w-20 h-20 rounded-full border-4 border-white/30 p-1 flex items-center justify-center">
                <div className="w-full h-full bg-white rounded-full" />
              </button>
            </div>
          </div>
        )}

        {(state === ScanState.IDENTIFYING || state === ScanState.SEARCHING) && renderLoadingOverlay()}

        {state === ScanState.CONFIRMING && (
          <div className="space-y-6 animate-in slide-in-from-bottom-5">
            {/* Image Preview */}
            <div className="bg-white rounded-[2.5rem] overflow-hidden shadow-lg border border-slate-100">
              {image && <img src={image} className="w-full h-48 object-cover opacity-90" />}

              <div className="p-8 space-y-6">
                <div className="flex items-center gap-2 mb-2">
                  <HelpCircle className="w-4 h-4 text-indigo-500" />
                  <p className="text-indigo-600 text-[11px] font-black uppercase tracking-widest">{t.confirmItem}</p>
                </div>

                {/* Editable Area - Robust Contrast */}
                <div className="relative bg-slate-50 rounded-3xl p-5 border-2 border-indigo-50 focus-within:border-indigo-500 transition-all">
                  <input 
                    type="text"
                    value={itemName}
                    onChange={(e) => setItemName(e.target.value)}
                    className="w-full bg-transparent text-3xl font-black text-slate-900 outline-none tracking-tight py-1"
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2 text-slate-300 pointer-events-none">
                    <Edit3 className="w-5 h-5" />
                  </div>
                  <p className="mt-2 text-[10px] text-slate-400 font-bold uppercase tracking-wider">{t.editing}</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <button onClick={reset} className="py-5 bg-slate-100 rounded-3xl font-black text-slate-500 active:scale-95 transition-all">재촬영</button>
                  <button onClick={handlePriceSearch} className="py-5 bg-indigo-600 text-white rounded-3xl font-black shadow-lg shadow-indigo-100 active:scale-95 transition-all">{t.searchBtn}</button>
                </div>
              </div>
            </div>
          </div>
        )}

        {state === ScanState.RESULT && priceData && (
          <div className="space-y-6 animate-in slide-in-from-bottom-8">
            <div className="bg-white rounded-[3rem] p-8 shadow-xl border border-slate-100 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-8 opacity-5"><Tag className="w-32 h-32 rotate-12" /></div>
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-50 rounded-xl"><CheckCircle className="w-5 h-5 text-indigo-600" /></div>
                  <h2 className="text-2xl font-black text-slate-900 tracking-tight">{itemName}</h2>
                </div>
              </div>
              <div className="bg-slate-900 p-8 rounded-[2.5rem] text-center shadow-2xl">
                <div className="flex flex-col gap-1">
                  <span className="text-5xl font-black text-white tracking-tighter">{priceData.priceRange}</span>
                  <span className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-2">VND • {priceData.unit}</span>
                </div>
              </div>
            </div>

            <div className="bg-amber-400 p-8 rounded-[2.5rem] flex gap-5 shadow-xl relative overflow-hidden">
              <div className="absolute -bottom-4 -right-4 opacity-10"><Lightbulb className="w-24 h-24" /></div>
              <div className="p-3 bg-white/20 rounded-2xl h-fit"><Zap className="w-6 h-6 text-white" /></div>
              <div className="space-y-2">
                <p className="font-black text-amber-900 text-[10px] uppercase tracking-widest">{t.negotiation}</p>
                <p className="text-lg font-black text-amber-900 leading-tight tracking-tight">{priceData.negotiationTip}</p>
              </div>
            </div>

            <div className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 mb-4 uppercase tracking-widest">{t.details}</p>
              <p className="text-slate-600 font-bold leading-relaxed text-sm">{priceData.description}</p>
            </div>
            <button onClick={reset} className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black text-xl shadow-2xl active:scale-95 transition-all mb-8">{t.reset}</button>
          </div>
        )}

        {state === ScanState.MANUAL_INPUT && (
          <div className="h-full flex flex-col items-center pt-20 space-y-10 animate-in slide-in-from-bottom-5">
            <div className="bg-indigo-600/10 p-10 rounded-[3rem] shadow-inner"><Database className="w-14 h-14 text-indigo-600" /></div>
            <div className="w-full space-y-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-indigo-600 uppercase tracking-widest ml-4">Item Name</label>
                <input 
                  type="text" 
                  value={itemName} 
                  onChange={(e) => setItemName(e.target.value)}
                  placeholder={t.searchPlaceholder}
                  className="w-full p-6 bg-white border-2 border-slate-100 rounded-[2rem] text-2xl font-black focus:border-indigo-600 outline-none transition-all shadow-sm"
                />
              </div>
              <button 
                onClick={handlePriceSearch} 
                disabled={!itemName} 
                className="w-full py-6 bg-indigo-600 disabled:bg-slate-200 text-white rounded-[2rem] font-black text-xl shadow-xl active:scale-95 transition-all"
              >
                {t.searchBtn}
              </button>
            </div>
          </div>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default ScannerTab;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Camera, RotateCcw, CheckCircle, XCircle, Search, Info, Loader2,
  ChevronRight, ScanLine, Sparkles, Tag, Lightbulb, ExternalLink,
  Keyboard, Edit3, X, Zap, Globe, Database, HelpCircle, TrendingUp, Coins
} from 'lucide-react';
import { identifyItem, getAveragePrice, PriceResult } from '../services/geminiService';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

enum ScanState { IDLE, CAPTURING, IDENTIFYING, CONFIRMING, SEARCHING, RESULT, MANUAL_INPUT }

interface Props { lang: Language; }

// 환율 상수 (대략적인 기준: 100 VND = 5.4 KRW)
const VND_TO_KRW_RATE = 0.054;

const ScannerTab: React.FC<Props> = ({ lang }) => {
  const [state, setState] = useState<ScanState>(ScanState.IDLE);
  const [isCameraLoading, setIsCameraLoading] = useState(false);
  const [image, setImage] = useState<string | null>(null);
  const [itemName, setItemName] = useState<string>('');
  const [priceData, setPriceData] = useState<PriceResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loadingStep, setLoadingStep] = useState(0);
  const t = TRANSLATIONS[lang];

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const loadingMessages = state === ScanState.IDENTIFYING 
    ? ["이미지 실시간 분석 중...", "달랏 특산품 데이터 매칭 중...", "사물 형태 파악 완료!"]
    : ["Google 실시간 시세 검색 중...", "현지 블로그 데이터 대조 중...", "합리적인 흥정 가격 산출 중..."];

  useEffect(() => {
    let interval: number;
    if (state === ScanState.IDENTIFYING || state === ScanState.SEARCHING) {
      setLoadingStep(0);
      interval = window.setInterval(() => {
        setLoadingStep(prev => (prev + 1) % loadingMessages.length);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [state]);

  const initCamera = async () => {
    setIsCameraLoading(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' } 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.onloadedmetadata = () => {
          setIsCameraLoading(false);
          videoRef.current?.play().catch(console.error);
        };
      }
    } catch (err) {
      setError(t.identifyFailed);
      setState(ScanState.IDLE);
    }
  };

  useEffect(() => {
    if (state === ScanState.CAPTURING) initCamera();
    return () => {
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    };
  }, [state]);

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);
        setImage(dataUrl);
        if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
        handleIdentify(dataUrl.split(',')[1]);
      }
    }
  };

  const handleIdentify = async (base64: string) => {
    setState(ScanState.IDENTIFYING);
    try {
      const result = await identifyItem(base64, lang);
      setItemName(result.itemName);
      setState(ScanState.CONFIRMING);
    } catch (err) {
      setError(t.identifyFailed);
      setState(ScanState.IDLE);
    }
  };

  const handlePriceSearch = async () => {
    if (!itemName.trim()) return;
    setState(ScanState.SEARCHING);
    try {
      const result = await getAveragePrice(itemName, lang);
      setPriceData(result);
      setState(ScanState.RESULT);
    } catch (err) {
      setError(t.priceFailed);
      setState(ScanState.CONFIRMING);
    }
  };

  const reset = () => {
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    setImage(null); setItemName(''); setPriceData(null); setError(null); setState(ScanState.IDLE);
  };

  // 텍스트에서 숫자만 추출하여 KRW로 변환
  const convertToKrw = (priceStr: string) => {
    const numbers = priceStr.replace(/[^0-9]/g, '');
    if (!numbers) return null;
    const vndAmount = parseInt(numbers);
    const krwAmount = Math.round(vndAmount * VND_TO_KRW_RATE);
    return new Intl.NumberFormat('ko-KR').format(krwAmount);
  };

  const renderLoadingOverlay = () => (
    <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-12 animate-in fade-in duration-500 bg-white">
      <div className="relative">
        <div className="absolute inset-0 -m-8 border border-indigo-100 rounded-full animate-ping opacity-20" />
        <div className="relative w-32 h-32 bg-white rounded-full shadow-2xl flex items-center justify-center border border-indigo-50">
          <div className="absolute inset-2 border-2 border-dashed border-indigo-200 rounded-full animate-[spin_10s_linear_infinite]" />
          {state === ScanState.IDENTIFYING ? (
            <Zap className="w-12 h-12 text-indigo-600 animate-bounce" />
          ) : (
            <Globe className="w-12 h-12 text-indigo-600 animate-pulse" />
          )}
        </div>
      </div>
      <div className="space-y-4 max-w-xs">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight">
          {state === ScanState.IDENTIFYING ? "물건 분석 중..." : "최적가 검색 중..."}
        </h2>
        <div className="flex flex-col items-center gap-3">
          <div className="h-1.5 w-48 bg-slate-100 rounded-full overflow-hidden">
            <div 
              className="h-full bg-indigo-600 rounded-full transition-all duration-1000 ease-out" 
              style={{ width: `${((loadingStep + 1) / loadingMessages.length) * 100}%` }}
            />
          </div>
          <p className="text-indigo-600 font-black text-sm uppercase tracking-wider animate-pulse">
            {loadingMessages[loadingStep]}
          </p>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col h-full bg-slate-50 overflow-hidden">
      {/* Header */}
      <div className="p-4 bg-white border-b border-slate-100 flex justify-between items-center z-40 sticky top-0 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-1.5 rounded-lg">
            <ScanLine className="w-4 h-4 text-white" />
          </div>
          <h1 className="font-black text-slate-800 tracking-tight">{t.scannerTitle}</h1>
        </div>
        {state !== ScanState.IDLE && (
          <button onClick={reset} className="p-2.5 rounded-2xl bg-slate-100 text-slate-500 active:scale-90 transition-transform">
            <RotateCcw className="w-5 h-5" />
          </button>
        )}
      </div>

      <div className="flex-1 relative p-6 overflow-y-auto pb-32">
        {state === ScanState.IDLE && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-10 animate-in zoom-in-95">
            <div className="space-y-3">
              <div className="inline-flex items-center gap-2 px-3 py-1 bg-indigo-50 rounded-full text-indigo-600 text-[10px] font-black uppercase tracking-widest">
                <Sparkles className="w-3 h-3 fill-indigo-600" /> Powered by Gemini
              </div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter leading-[0.9]">{t.startTitle}</h2>
              <p className="text-slate-400 font-medium px-8">{t.startSub}</p>
            </div>
            <div className="w-full space-y-4">
              <button onClick={() => setState(ScanState.CAPTURING)} className="w-full p-8 bg-indigo-600 rounded-[2.5rem] flex items-center justify-between group shadow-xl shadow-indigo-200 active:scale-95 transition-all">
                <div className="flex items-center gap-5">
                  <div className="bg-white/20 p-4 rounded-2xl text-white"><Camera className="w-8 h-8" /></div>
                  <span className="text-2xl font-black text-white tracking-tight">{t.byCamera}</span>
                </div>
                <ChevronRight className="w-6 h-6 text-white opacity-50" />
              </button>
              <button onClick={() => setState(ScanState.MANUAL_INPUT)} className="w-full p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] flex items-center justify-between group active:scale-95 transition-all">
                <div className="flex items-center gap-5">
                  <div className="bg-slate-50 p-4 rounded-2xl text-slate-400"><Keyboard className="w-8 h-8" /></div>
                  <span className="text-2xl font-black text-slate-800 tracking-tight">{t.bySearch}</span>
                </div>
                <ChevronRight className="w-6 h-6 text-slate-300" />
              </button>
            </div>
          </div>
        )}

        {state === ScanState.CAPTURING && (
          <div className="fixed inset-0 bg-black z-[100] flex flex-col h-[100dvh]">
            <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-[110] pt-[env(safe-area-inset-top,24px)]">
              <button onClick={reset} className="p-4 bg-black/40 backdrop-blur-md rounded-full text-white"><X className="w-7 h-7" /></button>
            </div>
            <video ref={videoRef} autoPlay playsInline muted className="flex-1 object-cover w-full h-full" />
            <div className="absolute bottom-0 left-0 right-0 p-12 pb-[calc(2rem+env(safe-area-inset-bottom,64px))] flex justify-center bg-gradient-to-t from-black/90 to-transparent">
              <button onClick={captureImage} className="w-20 h-20 rounded-full border-4 border-white/30 p-1 flex items-center justify-center">
                <div className="w-full h-full bg-white rounded-full" />
              </button>
            </div>
          </div>
        )}

        {(state === ScanState.IDENTIFYING || state === ScanState.SEARCHING) && renderLoadingOverlay()}

        {state === ScanState.CONFIRMING && (
          <div className="space-y-6 animate-in slide-in-from-bottom-5">
            <div className="bg-white rounded-[2.5rem] overflow-hidden shadow-lg border border-slate-100">
              {image && <img src={image} className="w-full h-48 object-cover opacity-90" />}
              <div className="p-8 space-y-6">
                <div className="flex items-center gap-2 mb-2">
                  <HelpCircle className="w-4 h-4 text-indigo-500" />
                  <p className="text-indigo-600 text-[11px] font-black uppercase tracking-widest">{t.confirmItem}</p>
                </div>
                <div className="relative bg-slate-50 rounded-3xl p-5 border-2 border-indigo-50 focus-within:border-indigo-500 transition-all">
                  <input 
                    type="text"
                    value={itemName}
                    onChange={(e) => setItemName(e.target.value)}
                    className="w-full bg-transparent text-3xl font-black text-slate-900 outline-none tracking-tight py-1"
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none">
                    <Edit3 className="w-5 h-5" />
                  </div>
                  <p className="mt-2 text-[10px] text-slate-400 font-bold uppercase tracking-wider">{t.editing}</p>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <button onClick={reset} className="py-5 bg-slate-100 rounded-3xl font-black text-slate-500 active:scale-95 transition-all">재촬영</button>
                  <button onClick={handlePriceSearch} className="py-5 bg-indigo-600 text-white rounded-3xl font-black shadow-lg shadow-indigo-100 active:scale-95 transition-all">{t.searchBtn}</button>
                </div>
              </div>
            </div>
          </div>
        )}

        {state === ScanState.RESULT && priceData && (
          <div className="space-y-6 animate-in slide-in-from-bottom-10 duration-500">
            {/* Main Price Card */}
            <div className="bg-white rounded-[3rem] p-8 shadow-2xl border border-slate-100 relative overflow-hidden">
              <div className="absolute -top-10 -right-10 opacity-[0.03] rotate-12">
                <TrendingUp className="w-64 h-64" />
              </div>

              <div className="flex items-center justify-between mb-8">
                <div className="space-y-1">
                  <p className="text-indigo-600 text-[10px] font-black uppercase tracking-[0.2em]">{t.priceResult}</p>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tighter">{itemName}</h2>
                </div>
                <div className="bg-indigo-50 p-3 rounded-2xl">
                  <Tag className="w-6 h-6 text-indigo-600" />
                </div>
              </div>

              {/* Price Display Area */}
              <div className="relative space-y-4">
                <div className="bg-gradient-to-br from-slate-900 to-indigo-950 p-8 rounded-[2.5rem] shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_50%_0%,rgba(99,102,241,0.15),transparent)] pointer-events-none" />

                  <div className="text-center space-y-1 relative z-10">
                    <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest mb-1">{t.recommended}</p>
                    <div className="flex flex-col gap-0">
                      <div className="flex items-baseline justify-center gap-2">
                        <span className="text-5xl font-black text-white tracking-tighter leading-none">
                          {priceData.priceRange}
                        </span>
                        <span className="text-indigo-300 font-black text-xl">VND</span>
                      </div>
                      <div className="flex items-center justify-center gap-1.5 mt-3 py-2 px-4 bg-white/5 rounded-full w-fit mx-auto border border-white/10">
                        <Coins className="w-3.5 h-3.5 text-amber-400" />
                        <span className="text-slate-300 font-bold text-sm">약</span>
                        <span className="text-white font-black text-lg tracking-tight">
                          {convertToKrw(priceData.priceRange) || '---'}
                        </span>
                        <span className="text-slate-300 font-bold text-sm">원</span>
                      </div>
                    </div>
                    <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-4">단위: {priceData.unit}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Negotiation Tip Card */}
            <div className="bg-amber-400 p-8 rounded-[3rem] shadow-xl shadow-amber-100/50 relative overflow-hidden group">
              <div className="absolute -bottom-6 -right-6 text-amber-900/10 group-hover:scale-110 transition-transform">
                <Lightbulb className="w-32 h-32" />
              </div>
              <div className="flex gap-5 items-start">
                <div className="p-4 bg-white/20 rounded-2xl backdrop-blur-sm shadow-inner">
                  <Zap className="w-6 h-6 text-amber-900" />
                </div>
                <div className="space-y-1.5 pr-8">
                  <p className="font-black text-amber-900 text-[10px] uppercase tracking-widest opacity-60">{t.negotiation}</p>
                  <p className="text-xl font-black text-amber-900 leading-[1.2] tracking-tight">
                    {priceData.negotiationTip}
                  </p>
                </div>
              </div>
