                    <Info className="w-3 h-3" />
                    기준: {priceData.unit}
                  </div>
                </div>

                {/* KRW Conversion - Highlighted Badge */}
                <div className="flex flex-col items-center gap-4 relative">
                  <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white p-2 rounded-full border border-slate-100 shadow-sm z-10">
