                  {/* KRW Conversion - Requested Format */}
                  <div className="bg-amber-100 border-2 border-amber-200 rounded-[2rem] py-5 px-6 inline-block shadow-sm w-full">
                    <p className="text-amber-800 text-[10px] font-black uppercase tracking-widest mb-1 opacity-70">한화 환산 금액 (KRW)</p>
